 class=\"kw\">this with</span> {\n      <span class=\"dc\">Level</span> = <span class=\"dc\">l</span>,\n      <span class=\"dc\">Settings</span> = <span class=\"kw\">new</span>(<span class=\"dc\">Settings</span>)\n    };\n}\n\n<span class=\"kw\">var</span> <span class=\"dc\">base</span> = <span class=\"kw\">new</span> <span class=\"cl\">GameConfig</span>(<span class=\"st\">\"L1\"</span>, <span class=\"nm\">3</span>,\n  <span class=\"kw\">new</span> { { <span class=\"st\">\"speed\"</span>, <span class=\"nm\">100</span> } });\n<span class=\"kw\">var</span> <span class=\"dc\">l2</span> = <span class=\"dc\">base</span>.<span class=\"fn\">CloneForLevel</span>(<span class=\"st\">\"L2\"</span>);", "Python": "<span class=\"kw\">import</span> copy\n<span class=\"kw\">from</span> dataclasses <span class=\"kw\">import</span> dataclass, field\n\n<span class=\"dc\">@dataclass</span>\n<span class=\"kw\">class</span> <span class=\"cl\">GameConfig</span>:\n  <span class=\"dc\">level</span>: <span class=\"kw\">str</span> = <span class=\"st\">\"L1\"</span>\n  <span class=\"dc\">lives</span>: <span class=\"kw\">int</span> = <span class=\"nm\">3</span>\n  <span class=\"dc\">settings</span>: <span class=\"kw\">dict</span> = <span class=\"dc\">field</span>(default_factory=<span class=\"kw\">dict</span>)\n\n  <span class=\"kw\">def</span> <span class=\"fn\">clone</span>(<span class=\"dc\">self</span>):\n    <span class=\"kw\">return</span> copy.<span class=\"fn\">deepcopy</span>(<span class=\"dc\">self</span>)\n\n\n<span class=\"dc\">base</span> = <span class=\"cl\">GameConfig</span>(<span class=\"dc\">settings</span>={<span class=\"st\">\"speed\"</span>: <span class=\"nm\">100</span>})\n<span class=\"dc\">l2</span> = <span class=\"dc\">base</span>.<span class=\"fn\">clone</span>()\n<span class=\"dc\">l2</span>.<span class=\"dc\">level</span> = <span class=\"st\">\"L2\"</span>", "Ruby": "<span class=\"kw\">class</span> <span class=\"cl\">GameConfig</span>\n  <span class=\"dc\">attr_accessor</span> <span class=\"st\">:level</span>, <span class=\"st\">:lives</span>, <span class=\"st\">:settings</span>\n\n  <span class=\"kw\">def</span> <span class=\"fn\">initialize</span>(<span class=\"dc\">level</span>, <span class=\"dc\">lives</span>, <span class=\"dc\">settings</span>)\n    <span class=\"dc\">@level</span>, <span class=\"dc\">@lives</span>, <span class=\"dc\">@settings</span> = <span class=\"dc\">level</span>, <span class=\"dc\">lives</span>, <span class=\"dc\">settings</span>\n  <span class=\"kw\">end</span>\n\n  <span class=\"kw\">def</span> <span class=\"fn\">clone</span>\n    <span class=\"cl\">Marshal</span>.<span class=\"fn\">load</span>(<span class=\"cl\">Marshal</span>.<span class=\"fn\">dump</span>(<span class=\"dc\">self</span>))\n  <span class=\"kw\">end</span>\n<span class=\"kw\">end</span>\n\n<span class=\"dc\">l2</span> = <span class=\"cl\">GameConfig</span>.<span class=\"fn\">new</span>(<span class=\"st\">\"L1\"</span>, <span class=\"nm\">3</span>, {speed: <span class=\"nm\">100</span>}).<span class=\"fn\">clone</span>\n<span class=\"dc\">l2</span>.<span class=\"dc\">level</span> = <span class=\"st\">\"L2\"</span>"}

